function solve(nums) {
    const N = nums.length;

    // DP[L] stores the maximum number of fixed points achievable 
    // in a subsequence of length L chosen from the elements processed so far.
    // Initialize DP[0] = 0. All others are set to negative infinity 
    // to indicate an unreachable state.
    const DP = new Array(N + 1).fill(Number.NEGATIVE_INFINITY);
    DP[0] = 0;

    // Iterate through the original array elements nums[i]
    for (let i = 0; i < N; i++) {
        const v = nums[i];

        // Iterate L downwards from i + 1 down to 1. 
        // L represents the potential new length of the subsequence if we include nums[i].
        // We iterate backward to ensure that DP[L-1] used in the calculation 
        // corresponds to the state *before* nums[i] was considered for length L-1.
        for (let L = i + 1; L >= 1; L--) {

            // Check if a valid subsequence of length L-1 exists.
            if (DP[L - 1] !== Number.NEGATIVE_INFINITY) {

                // Calculate fixed point gain: 1 if the current element v matches 
                // the target index L-1 (the index it will occupy in the new subsequence of length L).
                const fixedPointGain = (v === L - 1) ? 1 : 0;

                const newFixedPointCount = DP[L - 1] + fixedPointGain;

                // Update DP[L] by taking the maximum between its current value 
                // and the new count achievable by appending nums[i].
                DP[L] = Math.max(DP[L], newFixedPointCount);
            }
        }
    }

    // The maximum fixed point count is the maximum value found across all possible resulting subsequence lengths L.
    let maxFixedPoints = 0;
    for (let L = 0; L <= N; L++) {
        maxFixedPoints = Math.max(maxFixedPoints, DP[L]);
    }

    return maxFixedPoints;
}

